selector_to_html = {"a[href=\"examples/segmentation.html#caiman-docs-on-component-eval\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">12. </span>Caiman docs on component eval<a class=\"headerlink\" href=\"#caiman-docs-on-component-eval\" title=\"Permalink to this heading\">#</a></h1><p>https://caiman.readthedocs.io/en/latest/Getting_Started.html#component-evaluation</p>", "a[href=\"#documentation-contents\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Documentation Contents<a class=\"headerlink\" href=\"#documentation-contents\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"examples/motion_correction.html#registration-grid-search-if-you-need-it\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">7. </span>Registration Grid Search (if you need it!)<a class=\"headerlink\" href=\"#registration-grid-search-if-you-need-it\" title=\"Permalink to this heading\">#</a></h1><p>More runs with varying parameters, stored on disk in the dataframe batch.pickle</p>", "a[href=\"examples/assembly.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1. </span>LBM Step 1: Image Assembly<a class=\"headerlink\" href=\"#lbm-step-1-image-assembly\" title=\"Permalink to this heading\">#</a></h1><p>Raw ScanImage .tiff files are saved to disk in an interleaved manner.</p>", "a[href=\"examples/fastplotlib.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">26. </span>Fastplotlib Examples<a class=\"headerlink\" href=\"#fastplotlib-examples\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">26.1. </span>Smoothing with Gaussian Filter<a class=\"headerlink\" href=\"#smoothing-with-gaussian-filter\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#helpful-resources\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Helpful Resources<a class=\"headerlink\" href=\"#helpful-resources\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"examples/segmentation.html#cnmf-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">16. </span>CNMF outputs<a class=\"headerlink\" href=\"#cnmf-outputs\" title=\"Permalink to this heading\">#</a></h1><p>Similar to mcorr, you can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> API to fetch the outputs.</p><p><a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/api/cnmf.html\">API reference for mesmerize-CNMF</a>\n<a class=\"reference external\" href=\"https://caiman.readthedocs.io/en/latest/Getting_Started.html#parameters\">API reference for caiman-CNMF</a></p>", "a[href=\"examples/segmentation.html#reconstructed-background-b-f\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">19. </span>Reconstructed background - <code class=\"docutils literal notranslate\"><span class=\"pre\">b</span> <span class=\"pre\">*</span> <span class=\"pre\">f</span></code><a class=\"headerlink\" href=\"#reconstructed-background-b-f\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"examples/segmentation.html#data-paths-todo\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">13. </span>Data Paths (TODO)<a class=\"headerlink\" href=\"#data-paths-todo\" title=\"Permalink to this heading\">#</a></h1><p>The batch folder gets fairly cluttered with memmory mapped files.\nThis needs some cleaning before putting into tree form.</p>", "a[href=\"examples/collation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">25. </span>LBM Step 4: Collate Planes<a class=\"headerlink\" href=\"#lbm-step-4-collate-planes\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">25.1. </span>Get outputs for each z-plane<a class=\"headerlink\" href=\"#get-outputs-for-each-z-plane\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"examples/motion_correction.html#distinguishing-parameter-variants\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">8. </span>Distinguishing parameter variants<a class=\"headerlink\" href=\"#distinguishing-parameter-variants\" title=\"Permalink to this heading\">#</a></h1><p>We can see that there are many parameter variants, but it is not easy to see the differences in parameters between the rows that have the same <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code>.</p><p>We can use the <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman.get_params_diffs()</span></code> to see the unique parameters between rows with the same <code class=\"docutils literal notranslate\"><span class=\"pre\">item_name</span></code></p>", "a[href=\"user_guide/segmentation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4. </span>Segmentation<a class=\"headerlink\" href=\"#segmentation\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"examples/segmentation.html#residuals-y-ac-bf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">20. </span>Residuals - <code class=\"docutils literal notranslate\"><span class=\"pre\">Y</span> <span class=\"pre\">-</span> <span class=\"pre\">AC</span> <span class=\"pre\">-</span> <span class=\"pre\">bf</span></code><a class=\"headerlink\" href=\"#residuals-y-ac-bf\" title=\"Permalink to this heading\">#</a></h1><p>Mesmerize-core provides these outputs as lazy arrays. This allows you to work with arrays that would otherwise be hundreds of gigabytes or terabytes in size.</p>", "a[href=\"examples/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Examples<a class=\"headerlink\" href=\"#examples\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"examples/motion_correction.html#default-registration-parameters\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5. </span>Default registration parameters<a class=\"headerlink\" href=\"#default-registration-parameters\" title=\"Permalink to this heading\">#</a></h1><p>The parameters are passed <strong>directly</strong> to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>, this means you need to use the same exact names for the parameters and you can use all the parameters that you can use with <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code> - because it\u2019s just passing them to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p><p>The parameters dict for a mesmerize batch item must have the following structure. Put all the parameters in a dict under a key called <strong>main</strong>. The <strong>main</strong> dict is then fed directly to <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code>.</p>", "a[href=\"#comparison-with-lbm-caiman-matlab\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Comparison with <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-MATLAB/\">LBM-CaImAn-MATLAB</a><a class=\"headerlink\" href=\"#comparison-with-lbm-caiman-matlab\" title=\"Permalink to this heading\">#</a></h2><h3>Usage<a class=\"headerlink\" href=\"#usage\" title=\"Permalink to this heading\">#</a></h3><p>Beyond the obviously different programming language (MATLAB -&gt; Python), there are a few differences in how these pipelines were constructed.</p><p>The MATLAB implementation was essentially 4 functions spread across 4 <code class=\"docutils literal notranslate\"><span class=\"pre\">.m</span></code> files. These functions would be called from a user-made script (for example, <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-MATLAB/blob/master/demo_LBM_pipeline.m\">demo_LBM_pipeline.m</a>).</p>", "a[href=\"#usage\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Usage<a class=\"headerlink\" href=\"#usage\" title=\"Permalink to this heading\">#</a></h3><p>Beyond the obviously different programming language (MATLAB -&gt; Python), there are a few differences in how these pipelines were constructed.</p><p>The MATLAB implementation was essentially 4 functions spread across 4 <code class=\"docutils literal notranslate\"><span class=\"pre\">.m</span></code> files. These functions would be called from a user-made script (for example, <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-MATLAB/blob/master/demo_LBM_pipeline.m\">demo_LBM_pipeline.m</a>).</p>", "a[href=\"examples/segmentation.html#parameter-gridsearch\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">22. </span>Parameter Gridsearch<a class=\"headerlink\" href=\"#parameter-gridsearch\" title=\"Permalink to this heading\">#</a></h1><p>As shown for motion correction, the purpose of <code class=\"docutils literal notranslate\"><span class=\"pre\">mesmerize-core</span></code> is to perform parameter searches</p>", "a[href=\"examples/preprocessing.html#scan-phase-correction\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3. </span>Scan-phase correction<a class=\"headerlink\" href=\"#scan-phase-correction\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">3.1. </span>Percentile Filtering<a class=\"headerlink\" href=\"#percentile-filtering\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"examples/segmentation.html#interactive-parameter-exploration\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">17. </span>Interactive Parameter Exploration<a class=\"headerlink\" href=\"#interactive-parameter-exploration\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">17.1. </span>Temporal components, residuals<a class=\"headerlink\" href=\"#temporal-components-residuals\" title=\"Permalink to this heading\">#</a></h2><p>Many of the cnmf functions take a rich set of arguments</p>", "a[href=\"examples/segmentation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">11. </span>LBM Step 3: Segmentation<a class=\"headerlink\" href=\"#lbm-step-3-segmentation\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">11.1. </span>Segmentation: Extract neuronal locations and planar time-traces.<a class=\"headerlink\" href=\"#segmentation-extract-neuronal-locations-and-planar-time-traces\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"user_guide/assembly.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">1. </span>Image Assembly<a class=\"headerlink\" href=\"#image-assembly\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">1.1. </span>Overview<a class=\"headerlink\" href=\"#overview\" title=\"Permalink to this heading\">#</a></h2><p>Before running motion-correction or segmentation, we need to de-interleave raw <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code> files.</p><p>This is done internally with the <a class=\"reference external\" href=\"https://github.com/atlab/scanreader\">scanreader</a>.</p>", "a[href=\"#pipeline-overview\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Pipeline Overview<a class=\"headerlink\" href=\"#pipeline-overview\" title=\"Permalink to this heading\">#</a></h2><p>LBM-CaImAn-Pipeline uses <a class=\"reference external\" href=\"https://github.com/nel-lab/mesmerize-core/tree/master\">mesmerize-core</a> to interface with <a class=\"reference external\" href=\"https://github.com/flatironinstitute/CaImAn\">CaImAn</a> algorithms for Calcium Imaging data processing.</p><p>There are 4 steps in this pipeline:</p>", "a[href=\"user_guide/registration.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">3. </span>Registration<a class=\"headerlink\" href=\"#registration\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">3.1. </span>Overview<a class=\"headerlink\" href=\"#overview\" title=\"Permalink to this heading\">#</a></h2><p>We use <a class=\"reference external\" href=\"https://en.wikipedia.org/wiki/Image_registration\">image registration</a> to make sure that our neuron in the first frame is in the same spatial location as in frame N throughout the time-series.</p><p>As described in the <a class=\"reference internal\" href=\"user_guide/batch.html#batch\"><span class=\"std std-ref\">Batch</span></a>, registration can be run on your data by adding an <code class=\"docutils literal notranslate\"><span class=\"pre\">mcorr</span></code> item to the batch with parameters:</p>", "a[href=\"examples/motion_correction.html#first-registration-run-preset-with-good-defaults\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">6. </span>First registration run: preset with good defaults<a class=\"headerlink\" href=\"#first-registration-run-preset-with-good-defaults\" title=\"Permalink to this heading\">#</a></h1><p>Technical notes: On Linux &amp; Mac it will run in subprocess but on Windows it will run in the local kernel.</p>", "a[href=\"user_guide/collation.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">5. </span>Collation<a class=\"headerlink\" href=\"#collation\" title=\"Permalink to this heading\">#</a></h1><p>Placeholder (see the notebook)</p>", "a[href=\"user_guide/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">User Guide<a class=\"headerlink\" href=\"#user-guide\" title=\"Permalink to this heading\">#</a></h1><p>This section covers each step in the pipeline, parameters and metadata in more detail.</p>", "a[href=\"examples/segmentation.html#cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">14. </span>CNMF<a class=\"headerlink\" href=\"#cnmf\" title=\"Permalink to this heading\">#</a></h1><p>Perform CNMF using the mcorr output.</p><p>Similar to mcorr, put the CNMF params within the <code class=\"docutils literal notranslate\"><span class=\"pre\">main</span></code> key. The <code class=\"docutils literal notranslate\"><span class=\"pre\">refit</span></code> key will perform a second iteration, as shown in the <code class=\"docutils literal notranslate\"><span class=\"pre\">caiman</span></code> <code class=\"docutils literal notranslate\"><span class=\"pre\">demo_pipeline.ipynb</span></code> notebook.</p>", "a[href=\"api/index.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">API<a class=\"headerlink\" href=\"#api\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"examples/segmentation.html#load-outputs\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">24. </span>Load outputs<a class=\"headerlink\" href=\"#load-outputs\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"#performance\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Performance<a class=\"headerlink\" href=\"#performance\" title=\"Permalink to this heading\">#</a></h3><p>The primary pitfal of <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-MATLAB/\">LBM-CaImAn-MATLAB</a> are the memory constraints. Though MATLAB is extremely efficient with threaded internal functions, the lack of 3rd-party library support means reading and writing to well-established file-formats (i.e. <code class=\"docutils literal notranslate\"><span class=\"pre\">.tiff</span></code>, <code class=\"docutils literal notranslate\"><span class=\"pre\">.hdf5</span></code>) lacking modern features like <a class=\"reference external\" href=\"https://www.imperva.com/learn/performance/lazy-loading/\">lazy-loading data</a>. As a result, the memory footprint required to process a <em>N-GB dataset</em> will be <em>N-GB of memory</em>.</p><p>This pipeline utilizes the well-tested and optimized <a class=\"reference external\" href=\"https://pypi.org/project/tifffile/\">tifffile</a> to selectively load data only when it is needed. That is why processing a <code class=\"docutils literal notranslate\"><span class=\"pre\">35</span> <span class=\"pre\">GB</span></code> file will only consume ~<code class=\"docutils literal notranslate\"><span class=\"pre\">5</span> <span class=\"pre\">GB</span></code> of memory.</p>", "a[href=\"examples/segmentation.html#run-cnmf\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">15. </span>Run CNMF<a class=\"headerlink\" href=\"#run-cnmf\" title=\"Permalink to this heading\">#</a></h1><p>The API is identical to running mcorr.</p><p>You can provide the mcorr item row to <code class=\"docutils literal notranslate\"><span class=\"pre\">input_movie_path</span></code> and it will resolve the path of the input movie from the entry in the DataFrame.</p>", "a[href=\"examples/motion_correction.html#use-the-varients-to-organize-results-to-run-multiple-batch-items\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">9. </span>Use the varients to organize results to run multiple batch items.<a class=\"headerlink\" href=\"#use-the-varients-to-organize-results-to-run-multiple-batch-items\" title=\"Permalink to this heading\">#</a></h1><p><code class=\"docutils literal notranslate\"><span class=\"pre\">df.iterrows()</span></code> iterates through rows and returns the numerical index and row for each iteration</p>", "a[href=\"examples/segmentation.html#using-lazyarrays\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">21. </span>Using LazyArrays<a class=\"headerlink\" href=\"#using-lazyarrays\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"glossary.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Glossary<a class=\"headerlink\" href=\"#glossary\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"examples/motion_correction.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">4. </span>LBM Step 2: Registration<a class=\"headerlink\" href=\"#lbm-step-2-registration\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">4.1. </span>Registration: Correct for rigid/non-rigid movement<a class=\"headerlink\" href=\"#registration-correct-for-rigid-non-rigid-movement\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"examples/motion_correction.html#optional-cleanup-dataframe\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">10. </span>Optional, cleanup DataFrame<a class=\"headerlink\" href=\"#optional-cleanup-dataframe\" title=\"Permalink to this heading\">#</a></h1><p>Use the index that works best and all other items.</p><p>Remove batch items (i.e. rows) using <code class=\"docutils literal notranslate\"><span class=\"pre\">df.caiman.remove_item(&lt;item_uuid&gt;)</span></code>. This also cleans up the output data in the batch directory.</p>", "a[href=\"examples/segmentation.html#run-the-cnmf-batch-items\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">23. </span>Run the <code class=\"docutils literal notranslate\"><span class=\"pre\">cnmf</span></code> batch items<a class=\"headerlink\" href=\"#run-the-cnmf-batch-items\" title=\"Permalink to this heading\">#</a></h1>", "a[href=\"user_guide/batch.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2. </span>Batch<a class=\"headerlink\" href=\"#batch\" title=\"Permalink to this heading\">#</a></h1><p>Before continuing, users should review the <a class=\"reference external\" href=\"https://mesmerize-core.readthedocs.io/en/latest/user_guide.html\">mesmerize-core user guide</a>.</p><p>Functions in this section are just wrappers for mesmerize-core, and all of it\u2019s functionality can be directly used in your resulting batch dataframes.</p>", "a[href=\"examples/preprocessing.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">2. </span>Preprocessing<a class=\"headerlink\" href=\"#preprocessing\" title=\"Permalink to this heading\">#</a></h1><h2><span class=\"section-number\">2.1. </span>scanreader<a class=\"headerlink\" href=\"#scanreader\" title=\"Permalink to this heading\">#</a></h2>", "a[href=\"#lbm-caiman-python-documentation\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">LBM-CaImAn-Python Documentation<a class=\"headerlink\" href=\"#lbm-caiman-python-documentation\" title=\"Permalink to this heading\">#</a></h1><p>For the <code class=\"docutils literal notranslate\"><span class=\"pre\">MATLAB</span></code> implementation of this pipeline, see <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-MATLAB/\">here</a>.</p><p>For current installation instructions, see the project <a class=\"reference external\" href=\"https://github.com/MillerBrainObservatory/LBM-CaImAn-Python/blob/master/README.md\">README</a></p>", "a[href=\"examples/segmentation.html#reconstructed-movie-a-c\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\"><span class=\"section-number\">18. </span>Reconstructed movie - <code class=\"docutils literal notranslate\"><span class=\"pre\">A</span> <span class=\"pre\">*</span> <span class=\"pre\">C</span></code><a class=\"headerlink\" href=\"#reconstructed-movie-a-c\" title=\"Permalink to this heading\">#</a></h1>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
